    if pb:HasField("roleAttrPanel") then
        ---@type LxRoleAttrPanel
        local roleAttrPanel = ModuleCenter.Common:NewRoleAttrPanel(pb.roleAttrPanel)
        ModuleCenter.Role:SetRoleAttrPanel(roleAttrPanel)
        if roleAttrPanel.rolePower > 0 then
            CtrlCenter.Role:OnRolePowerChange(roleAttrPanel.rolePower)
        end
    end
    --
    --if pb:HasField("memoryStorePanel") then
    --    ---@type LxMemoryStorePanel
    --    local memoryStorePanel = ModuleCenter.Common:NewMemoryStorePanel(pb.memoryStorePanel)
    --    ModuleCenter.MemoryStore:SetMemoryStorePanel(memoryStorePanel)
    --end

    if pb:HasField("equipAttrPanel") then
        ---@type LxEquipPanel
        local EquipPanel = ModuleCenter.Common:NewEquipPanel(pb.equipAttrPanel)
        ModuleCenter.Role:SetEquipAttrPanel(EquipPanel)
    end

end

function LxCommonHandler:OnRewardsReceivedResp(pb)
--[[    local ctrl = MgrCenter.PanelMgr:GetPanelCtrl(UiNames.InstanceTurntable)
    if ctrl then
        --- 暂时特殊处理，后期需要和服务端对接
        FireEvent(EventNames.INSTANCE_SEND_REWARD,pb)
        return
    end]]
    ---@type number 奖励触发类型,1-充值 2-功能开启 3-非充值
    local type = pb.type
    ---@type LxThingsInfo 获得的奖励
    local thingsInfo = ModuleCenter.Common:NewThingsInfo(pb.thingsInfo)
    ---@type string
    local moreInfo = pb.moreInfo
    --购买队列礼包，先不弹窗
    local ctrl = MgrCenter.PanelMgr:GetPanelCtrl(UiNames.Queue)
    if(ctrl == nil)then
        ctrl = MgrCenter.PanelMgr:GetChildPanelCtrl(UiNames.Queue)
    end
    if(ctrl ~= nil)then
        FireEvent(EventNames.QUEUE_SHOP_BUY_RESULT,thingsInfo,moreInfo)
        return
    end

    FireEvent(EventNames.REWARDS_RECEIVED, type, thingsInfo, moreInfo)
end

function LxCommonHandler:CheckOfflineTimeReq(roleList)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.CheckOfflineTimeReq)
    for k, v in ipairs(roleList) do
        table.insert(proto.roleList, v)
    end
    SendMessage(LxProtoIds.CheckOfflineTimeReq, proto)
end

function LxCommonHandler:OnCheckOfflineTimeResp(pb)
    -- // 角色信息,只填充roleId和offlineTime
    local map = {}
    for _, v in ipairs(pb.offlineList) do
        map[v.roleId] = { offlineTime = v.offlineTime }
    end
    FireEvent(EventNames.ROLE_ONLINE_STATE, map)
end

