-- 全部点赞记录,登录下发
function LxCommonHandler:OnLikeDataResp(pb)
    local LxCommonModule = ModuleCenter.Common

    if #pb.objs > 0 then
        for k, v in ipairs(pb.objs) do
            LxCommonModule:SetLikeData(v)
        end
    else
        LxCommonModule:ClearLikeData()
    end

    FireEvent(EventNames.LIKE_DATA_CHANGE)
end

-- 点赞
function LxCommonHandler:LikeReq(refId, target)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.LikeReq)
    proto.refId = refId
    proto.target = target
    SendMessage(LxProtoIds.LikeReq, proto)
end

-- 点赞 返回
function LxCommonHandler:OnLikeResp(pb)
    local likeRefId = pb.refId

    local commonModule = ModuleCenter.Common
    local oldLikeData = commonModule:GetLikeData(likeRefId)
    local oldRecordIds = {}
    if oldLikeData then
        for k,v in pairs(oldLikeData.targets) do
            oldRecordIds[k] = true
        end
    end

    local likeTargetNum = 0
    local likeTargetIdMap = {}
    local data = ModuleCenter.Common:SetLikeData(pb.likeDataObj)
    if data then
        for k,v in pairs(data.targets) do
            if not oldRecordIds[k] then
                likeTargetNum = likeTargetNum + 1
                likeTargetIdMap[k] = true
            end
        end
    end
    FireEvent(EventNames.LIKE_DATA_CHANGE,{
        likeData = data,
        likeRefId = likeRefId,
        likeTargetNum = likeTargetNum,
        likeTargetIdMap = likeTargetIdMap,
    })

    if pb:HasField("thingsInfo") then
        FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.Like, pb.thingsInfo)
    end
end

function LxCommonHandler:RemoveNewDotReq(type,refIds)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.RemoveNewDotReq)
    proto.type = type
    for i,v in ipairs(refIds) do
        proto.refId:append(v)
    end
    SendMessage(LxProtoIds.RemoveNewDotReq, proto)
end

function LxCommonHandler:OnRemoveNewDotResp()

end
function LxCommonHandler:OnFunctionOpenDataResp(pb)
    ModuleCenter.FuncOpen:SetOpenList(pb)
    FireEvent(EventNames.FUNC_OPEN_CHANGE)
    self:CheckNewOpen()
end
--- 新功能开启
function LxCommonHandler:CheckNewOpen()
    local funcId = ModuleCenter.FuncOpen:GetNewOpenFuncId()
    if funcId then
        local isOpen = IsOpenPanel(UiNames.FuncOpenPop)
        local isOpenMain = IsOpenPanel(UiNames.MainCenter)
        if not isOpen and isOpenMain then
            ShowPanel(UiNames.FuncOpenPop, {funcId = funcId})
        end
    end
end
return LxCommonHandler
